{
  "domain_analysis": {
    "business_context": "Evolution of the Shipment aggregate from a 1:1 Shipment-Recipient relationship to a 1:N relationship. This is a fundamental structural change to a core domain entity in a delivery platform with 2M existing shipments and external partner API integrations. This is not a simple schema migration — it redefines what a Shipment *means* in the business.",
    "bounded_context": "Shipment Management / Delivery Operations",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A unit of goods being transported from origin to one or more delivery destinations. Post-change, a Shipment is a logical grouping that may fan out to multiple Recipients." },
      { "term": "Recipient", "definition": "A party who receives a delivery. Identified by name, address, phone number, and (post-change) individual delivery preferences." },
      { "term": "Delivery Preference", "definition": "Recipient-level configuration governing how and when delivery should occur (e.g., time windows, safe-place instructions, signature requirements, notification channels)." },
      { "term": "Primary Recipient", "definition": "The first or default Recipient on a multi-recipient Shipment. Critical for backward compatibility — any context that assumed a single recipient must resolve to the Primary Recipient." },
      { "term": "Shipment Status", "definition": "The aggregate delivery state of a Shipment. In a multi-recipient model, this becomes a composite: the Shipment is only 'Delivered' when ALL Recipients have received their delivery, or business rules define otherwise." },
      { "term": "Delivery Attempt", "definition": "A physical attempt to deliver to a specific Recipient. Post-change, delivery attempts are per-Recipient, not per-Shipment." },
      { "term": "External Partner API", "definition": "Third-party integrations that consume shipment data in the current single-recipient format. These represent a hard integration boundary." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment MUST have at least one Recipient. Zero-recipient Shipments are invalid.",
      "invariant": true,
      "invariant_justification": "A Shipment with no Recipient has no delivery destination and is physically meaningless. This is a data integrity constraint — the system is corrupt if this is violated.",
      "testable_assertion": "Any attempt to create or update a Shipment that would result in zero Recipients must be rejected with a validation error."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient on a Shipment MUST have a name, address, and phone number. These are non-nullable.",
      "invariant": true,
      "invariant_justification": "A delivery cannot be physically executed without knowing where to go (address), who to deliver to (name), and how to contact them (phone). This is a physical-world constraint.",
      "testable_assertion": "Creating a Recipient with any of name, address, or phone as null/empty must be rejected."
    },
    {
      "id": "BR-3",
      "rule": "Each Recipient on a Shipment MUST have a unique address. Duplicate addresses within the same Shipment are not allowed.",
      "invariant": true,
      "invariant_justification": "Two Recipients at the same address on the same Shipment is either a data entry error or should be a single Recipient. Allowing duplicates corrupts delivery routing and billing.",
      "testable_assertion": "Adding a Recipient whose address matches an existing Recipient on the same Shipment must be rejected."
    },
    {
      "id": "BR-4",
      "rule": "Every multi-recipient Shipment MUST designate exactly one Primary Recipient for backward compatibility and default resolution.",
      "invariant": true,
      "invariant_justification": "External APIs, billing, notifications, and any legacy code path that assumed a single recipient must have a deterministic way to resolve 'the' recipient. Without a Primary, these paths produce undefined behavior.",
      "testable_assertion": "A Shipment with multiple Recipients must have exactly one marked as Primary. Removing the Primary Recipient must either promote another or be rejected."
    },
    {
      "id": "BR-5",
      "rule": "Delivery preferences are owned by each Recipient independently and do not cascade from the Shipment level.",
      "invariant": false,
      "invariant_justification": "This is a policy decision. The business could later decide to support Shipment-level defaults that Recipients inherit. It is not a data integrity constraint.",
      "testable_assertion": "Updating delivery preferences on Recipient A must not affect Recipient B on the same Shipment."
    },
    {
      "id": "BR-6",
      "rule": "Shipment-level status must be derived from the statuses of all its Recipient-level deliveries. A Shipment is 'Delivered' only when ALL Recipients have status 'Delivered'. A Shipment is 'Partially Delivered' when at least one but not all Recipients have been delivered to.",
      "invariant": false,
      "invariant_justification": "The status rollup logic is a business policy. A VP could decide that a Shipment is 'Delivered' when the Primary Recipient receives it, for example. The specific rollup rule is policy, not physics.",
      "testable_assertion": "Given a Shipment with 3 Recipients where 2 are Delivered and 1 is In Transit, the Shipment status must be 'Partially Delivered'."
    },
    {
      "id": "BR-7",
      "rule": "All 2 million existing single-recipient Shipments must be migrated such that their existing Recipient becomes the Primary Recipient with no loss of data or change in external API behavior.",
      "invariant": true,
      "invariant_justification": "Data loss or behavioral change to existing records is a corruption event. The migration must be lossless and semantically preserving.",
      "testable_assertion": "After migration, querying any pre-existing Shipment must return the same Recipient data as before, and the Recipient must be flagged as Primary."
    },
    {
      "id": "BR-8",
      "rule": "External partner APIs MUST continue to receive shipment data in single-recipient format until partners explicitly opt in to the multi-recipient schema.",
      "invariant": true,
      "invariant_justification": "Breaking an external API contract is a contract violation that can cause partner system failures, SLA breaches, and legal exposure. This is a hard integration constraint.",
      "testable_assertion": "For partners on the legacy API version, a multi-recipient Shipment must be serialized with only the Primary Recipient. No array structure or additional recipients may appear in the payload."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new Shipment is being created",
      "when": "The request includes two or more Recipients with valid name, address, phone, and distinct addresses",
      "then": "The Shipment is created with all Recipients persisted, one designated as Primary, and each with their own delivery preferences"
    },
    {
      "id": "AC-2",
      "given": "A new Shipment is being created",
      "when": "The request includes zero Recipients",
      "then": "The request is rejected with a validation error stating at least one Recipient is required"
    },
    {
      "id": "AC-3",
      "given": "An existing single-recipient Shipment (pre-migration)",
      "when": "The data migration is executed",
      "then": "The Recipient is preserved with all original fields intact and flagged as Primary Recipient"
    },
    {
      "id": "AC-4",
      "given": "A multi-recipient Shipment exists",
      "when": "An external partner on the legacy API version requests shipment data",
      "then": "The response contains only the Primary Recipient in the original single-recipient format with no schema breaking changes"
    },
    {
      "id": "AC-5",
      "given": "A Shipment has 3 Recipients and 2 have been delivered",
      "when": "The Shipment status is queried",
      "then": "The status is 'Partially Delivered' and individual Recipient delivery statuses are available"
    },
    {
      "id": "AC-6",
      "given": "A multi-recipient Shipment exists",
      "when": "A user attempts to remove the last remaining Recipient",
      "then": "The operation is rejected to preserve the minimum-one-Recipient invariant"
    },
    {
      "id": "AC-7",
      "given": "A multi-recipient Shipment exists",
      "when": "A user attempts to add a Recipient with the same address as an existing Recipient on that Shipment",
      "then": "The operation is rejected with a duplicate-address validation error"
    },
    {
      "id": "AC-8",
      "given": "A multi-recipient Shipment with a designated Primary Recipient",
      "when": "The Primary Recipient is removed and other Recipients remain",
      "then": "Either a new Primary is automatically promoted (e.g., next in order) or the operation is rejected until a new Primary is designated"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A Shipment has 50 Recipients — what is the upper bound?",
      "expected_behavior": "The spec does not define a maximum. The business must define an upper limit to prevent abuse, routing complexity explosion, and UI/UX degradation. Recommend defining a configurable max (e.g., 10 or 20) as a soft policy."
    },
    {
      "scenario": "Two Recipients on the same Shipment have the same phone number but different addresses",
      "expected_behavior": "This is valid. Phone number uniqueness is NOT required within a Shipment — only address uniqueness is. Example: a parent sending gifts to two of their children at different dorms."
    },
    {
      "scenario": "A Recipient's address is updated to match another Recipient's address on the same Shipment",
      "expected_behavior": "The update must be rejected per the duplicate-address invariant (BR-3)."
    },
    {
      "scenario": "Billing and pricing: does a multi-recipient Shipment cost more?",
      "expected_behavior": "The spec is silent on pricing. Multi-recipient shipments involve multiple delivery stops, so pricing, ETAs, and routing all need to account for N destinations. This must be defined before implementation."
    },
    {
      "scenario": "Delivery failure for one Recipient: does it block the entire Shipment?",
      "expected_behavior": "Per BR-6, delivery to each Recipient is tracked independently. A failed delivery to Recipient A does not prevent delivery to Recipient B. The Shipment status reflects the aggregate ('Partially Delivered', 'Delivered with Exceptions', etc.)."
    },
    {
      "scenario": "Concurrent modifications: two users add/remove Recipients on the same Shipment simultaneously",
      "expected_behavior": "Optimistic concurrency control must be enforced at the Shipment aggregate level to prevent the invariant (min 1 Recipient, unique addresses, exactly 1 Primary) from being violated by race conditions."
    },
    {
      "scenario": "Webhooks and event consumers that expect single-recipient payloads",
      "expected_behavior": "All event schemas that include Recipient data must be versioned. Legacy consumers must receive the Primary Recipient only. New consumers can opt into the multi-recipient event schema."
    },
    {
      "scenario": "Search and filtering: 'find shipments for recipient X'",
      "expected_behavior": "Search must now match against ALL Recipients on a Shipment, not just 'the' Recipient. Indexes may need to change from 1:1 to 1:N."
    }
  ],

  "business_impact": {
    "financial": "Multi-recipient shipments enable new revenue streams (gift splitting, group orders, business distribution). However, pricing model must be redefined — a single-fee-per-shipment model undercharges for multi-stop deliveries. Migration cost is non-trivial: 2M records to transform, partner API versioning, and extended QA across all integration points.",
    "operational": "Routing complexity increases significantly — the system moves from single-destination to multi-stop optimization (a fundamentally harder problem). Delivery tracking, SLA measurement, and exception handling all become per-Recipient, multiplying operational surface area. Customer support must be retrained on 'Partially Delivered' states and per-Recipient issue resolution.",
    "user": "End users gain flexibility (send to multiple people in one order). However, UX complexity increases: shipment tracking now shows multiple delivery statuses, notifications multiply, and the 'Where is my package?' experience fragments. UI must clearly communicate per-Recipient status without overwhelming users.",
    "risk": "HIGH. This change touches the core domain entity. Risks include: (1) Data migration failure corrupting 2M existing records, (2) External partner API breakage causing SLA violations and partner churn, (3) Billing miscalculation on multi-recipient shipments, (4) Event schema changes breaking downstream consumers, (5) Performance degradation from 1:N joins on a high-volume table. Rollback is extremely difficult once multi-recipient data exists in production.",
    "stakeholders_affected": [
      { "group": "End Customers (Senders)", "impact": "Gain multi-recipient capability; may face UX complexity increase; existing shipment behavior must not change" },
      { "group": "End Customers (Recipients)", "impact": "No change to their experience if they are the only Recipient; may receive partial-shipment notifications on multi-recipient orders" },
      { "group": "External Partners / API Consumers", "impact": "Critical — must not experience any breaking change. Legacy format must be preserved. Partners must be given opt-in migration path and timeline." },
      { "group": "Courier / Delivery Drivers", "impact": "Routing and delivery workflow changes — a single Shipment now means multiple stops. Driver apps must show per-Recipient delivery instructions and capture per-Recipient proof of delivery." },
      { "group": "Customer Support", "impact": "Must handle 'Partially Delivered' states, per-Recipient issues, and more complex dispute resolution. Training and tooling updates required." },
      { "group": "Finance / Billing", "impact": "Pricing model must account for multi-stop cost. Invoicing, refunds, and chargebacks become per-Recipient or require new aggregation logic." },
      { "group": "Engineering / Platform", "impact": "Schema migration on 2M+ records, API versioning, event schema evolution, search index changes, and performance testing for 1:N relationships on core entities." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec clearly states the structural change (1:1 to 1:N) but is silent on several critical business dimensions: pricing model, maximum recipient count, status rollup policy, delivery failure handling, and partner migration timeline. These are not implementation details — they are fundamental business decisions that change what 'correct' means. Without them, acceptance criteria for billing, status, and partner integration are based on reasonable assumptions, not confirmed requirements.",
    "high_confidence_areas": [
      "Minimum one Recipient invariant",
      "Backward compatibility requirement for existing data",
      "External partner API must not break",
      "Recipient requires name, address, phone",
      "Delivery preferences are per-Recipient"
    ],
    "low_confidence_areas": [
      "Status rollup policy (all delivered vs primary delivered vs majority delivered)",
      "Pricing model for multi-recipient shipments",
      "Maximum number of Recipients per Shipment",
      "Primary Recipient promotion rules when Primary is removed",
      "Whether delivery preferences have a defined schema or are freeform",
      "Partner API migration timeline and opt-in mechanism"
    ],
    "assumptions": [
      "A 'Primary Recipient' concept is needed for backward compatibility — not stated in spec but inferred from the integration constraint",
      "Address uniqueness per Shipment is required — inferred from domain logic, not stated",
      "Status rollup follows ALL-delivered semantics — reasonable default but not specified",
      "Delivery preferences are Recipient-owned, not inherited from Shipment-level defaults"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not define how Shipment-level status is derived from per-Recipient statuses. Is a Shipment 'Delivered' when all Recipients receive delivery, when the Primary does, or some other rule? This affects tracking UX, SLA measurement, and partner reporting.",
      "affected_stakeholders": ["End Customers", "Customer Support", "External Partners", "Operations"],
      "options": [
        "A: Shipment is Delivered only when ALL Recipients are Delivered",
        "B: Shipment is Delivered when Primary Recipient is Delivered; others tracked separately",
        "C: Introduce 'Partially Delivered' as a first-class status with configurable completion rules"
      ],
      "recommendation": "Option C — it is the most operationally honest and gives the business flexibility to tune rollup rules without code changes."
    },
    {
      "type": "missing_context",
      "description": "No pricing model defined for multi-recipient shipments. A Shipment to 5 addresses costs dramatically more to fulfill than one to 1 address. Without a pricing rule, billing will either undercharge (revenue loss) or the feature cannot launch.",
      "affected_stakeholders": ["Finance / Billing", "End Customers", "Product"],
      "options": [
        "A: Price per Recipient (base + per-stop fee)",
        "B: Price per Shipment with tiered recipient bands",
        "C: Defer pricing to a separate workstream but block multi-recipient creation in billing until resolved"
      ],
      "recommendation": "Option C as a short-term gate, with Option A as the likely long-term model. Do NOT launch multi-recipient without a billing answer."
    },
    {
      "type": "ambiguity",
      "description": "No maximum number of Recipients per Shipment is specified. Unbounded recipient lists create routing complexity (approaches TSP), performance risk on queries, and potential for abuse.",
      "affected_stakeholders": ["Engineering", "Operations", "Delivery Drivers"],
      "options": [
        "A: Hard cap at 10 Recipients",
        "B: Configurable per-customer tier (e.g., standard: 5, enterprise: 50)",
        "C: No limit, rely on pricing to discourage abuse"
      ],
      "recommendation": "Option B — it protects the system while allowing enterprise use cases. Must be defined before implementation."
    },
    {
      "type": "missing_context",
      "description": "The backward compatibility strategy for external partner APIs is implied but not specified. Need to know: Will there be a v2 API? What is the partner migration timeline? Is the legacy format maintained indefinitely or sunset?",
      "affected_stakeholders": ["External Partners", "Engineering", "Product"],
      "options": [
        "A: Introduce v2 API, maintain v1 indefinitely",
        "B: Introduce v2 API, deprecate v1 with 12-month sunset",
        "C: Extend v1 with optional multi-recipient fields (backward compatible extension)"
      ],
      "recommendation": "Option B with Option C as a bridge. Partners need a clear timeline, and indefinite dual-maintenance is expensive."
    }
  ],

  "rejection_reasons": []
}

